### 3. **API へのデータフェッチ方法**

#### 認証情報の付与

**Supabaseクライアント:**

```typescript
// lib/supabase/server.ts
import { createServerClient } from '@supabase/ssr';
import { cookies } from 'next/headers';

export async function createClient() {
  const cookieStore = await cookies();
  return createServerClient(url, anonKey, { cookies: {...} });
}
```

#### データフェッチ関数（RSC用）

**profile.data.ts の実装例**

```typescript
export async function getProfile(): Promise<GetProfileResult> {
  const supabase = await createClient();
  const { data: { session } } = await supabase.auth.getSession();

  if (!session) return { success: false, code: "UNAUTHORIZED" };

  const response = await fetch(
    `${process.env.API_URL}/v1/users/${session.user.id}`,
    { headers: { Authorization: `Bearer ${session.access_token}` } }
  );

  if (response.status === 404) return { success: false, code: "NOT_FOUND" };
  if (!response.ok) return { success: false, code: "INTERNAL_ERROR" };

  return { success: true, profile: await response.json() };
}
```

#### Server Actions（データ更新用）

**profile-edit.action.ts の実装例**

```typescript
"use server";

export async function editProfile(nickname: string, introduce: string) {
  const supabase = await createClient();
  const { data: { session } } = await supabase.auth.getSession();

  if (!session) return { success: false, code: "UNAUTHORIZED" };

  const response = await fetch(
    `${process.env.API_URL}/v1/users/${session.user.id}`,
    {
      method: "PATCH",
      headers: {
        Authorization: `Bearer ${session.access_token}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ nickname, introduce })
    }
  );

  return response.ok
    ? { success: true }
    : { success: false, code: "UPDATE_FAILED" };
}
```

#### エラーハンドリング

**Result型パターン（型安全なエラー処理）**

```typescript
type GetProfileResult = 
  | { success: true; profile: Profile }
  | { success: false; code: "UNAUTHORIZED" | "NOT_FOUND" | "INTERNAL_ERROR" };

// 呼び出し側で型チェック
const profile = handleGetProfileResult(await getProfile());
```

**handle-get-profile-result.server.ts**

```typescript
export function handleGetProfileResult(result: GetProfileResult): Profile {
  if (result.success) return result.profile;

  switch (result.code) {
    case "UNAUTHORIZED": redirect("/login");
    case "NOT_FOUND": notFound();
    case "INTERNAL_ERROR": throw new Error("取得失敗");
  }
}
```

