1	package auth
2	
3	import (
4		"crypto/ecdsa"
5		"crypto/elliptic"
6		"encoding/base64"
7		"encoding/json"
8		"errors"
9		"math/big"
10		"net/http"
11		"strings"
12	
13		"github.com/golang-jwt/jwt/v5"
14	)
15	
16	var ErrUnauthorized = errors.New("unauthorized")
17	
18	type jwk struct {
19		Kid string `json:"kid"`
20		Kty string `json:"kty"`
21		Crv string `json:"crv"`
22		X   string `json:"x"`
23		Y   string `json:"y"`
24	}
25	
26	type jwks struct {
27		Keys []jwk `json:"keys"`
28	}
29	
30	type Verifier struct {
31		jwtSecret string
32		ecKeys    map[string]*ecdsa.PublicKey
33	}
34	
35	func NewVerifier(jwtSecret, supabaseURL string) *Verifier {
36		v := &Verifier{
37			jwtSecret: jwtSecret,
38			ecKeys:    make(map[string]*ecdsa.PublicKey),
39		}
40		_ = v.fetchJWKS(supabaseURL)
41		return v
42	}
43	
44	func (v *Verifier) fetchJWKS(supabaseURL string) error {
45		resp, err := http.Get(supabaseURL + "/auth/v1/.well-known/jwks.json") //nolint:gosec
46		if err != nil {
47			return err
48		}
49		defer resp.Body.Close()
50	
51		var ks jwks
52		if err := json.NewDecoder(resp.Body).Decode(&ks); err != nil {
53			return err
54		}
55	
56		for _, k := range ks.Keys {
57			if k.Kty != "EC" || k.Crv != "P-256" || k.Kid == "" {
58				continue
59			}
60			xBytes, err := base64.RawURLEncoding.DecodeString(k.X)
61			if err != nil {
62				continue
63			}
64			yBytes, err := base64.RawURLEncoding.DecodeString(k.Y)
65			if err != nil {
66				continue
67			}
68			v.ecKeys[k.Kid] = &ecdsa.PublicKey{
69				Curve: elliptic.P256(),
70				X:     new(big.Int).SetBytes(xBytes),
71				Y:     new(big.Int).SetBytes(yBytes),
72			}
73		}
74		return nil
75	}
76	
77	func (v *Verifier) Verify(tokenString string) error {
78		_, err := jwt.Parse(tokenString, v.keyFunc)
79		if err != nil {
80			return ErrUnauthorized
81		}
82		return nil
83	}
84	
85	func (v *Verifier) GetUserID(tokenString string) (string, error) {
86		token, err := jwt.Parse(tokenString, v.keyFunc)
87		if err != nil {
88			return "", ErrUnauthorized
89		}
90	
91		claims, ok := token.Claims.(jwt.MapClaims)
92		if !ok {
93			return "", ErrUnauthorized
94		}
95	
96		sub, ok := claims["sub"].(string)
97		if !ok || sub == "" {
98			return "", ErrUnauthorized
99		}
100	
101		return sub, nil
102	}
103	
104	func (v *Verifier) keyFunc(token *jwt.Token) (any, error) {
105		switch token.Method.(type) {
106		case *jwt.SigningMethodHMAC:
107			return []byte(v.jwtSecret), nil
108		case *jwt.SigningMethodECDSA:
109			kid, ok := token.Header["kid"].(string)
110			if !ok {
111				return nil, ErrUnauthorized
112			}
113			key, ok := v.ecKeys[kid]
114			if !ok {
115				return nil, ErrUnauthorized
116			}
117			return key, nil
118		default:
119			return nil, ErrUnauthorized
120		}
121	}
122	
123	func ExtractBearerToken(r *http.Request) (string, error) {
124		header := r.Header.Get("Authorization")
125		if !strings.HasPrefix(header, "Bearer ") {
126			return "", ErrUnauthorized
127		}
128		return strings.TrimPrefix(header, "Bearer "), nil
129	}
