"use client";

import type { JSX } from "react";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import type { ApiKey } from "./api-keys.data";

const dateFormatter = new Intl.DateTimeFormat("ja-JP", {
  dateStyle: "medium",
});

function formatDate(value: string): string {
  if (value === "infinity") return "無期限";
  if (value === "") return "—";
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return value;
  return dateFormatter.format(parsed);
}

interface Props {
  apiKeys?: ApiKey[];
  disabled?: boolean;
}

const SKELETON_ROWS: ApiKey[] = Array.from({ length: 3 }, (_, i) => ({
  apiKeyId: `skeleton-${i}`,
  suffix: "",
  createdAt: "",
  expiredAt: "",
}));

export function ApiKeysListPresenter({
  apiKeys = [],
  disabled = false,
}: Props): JSX.Element {
  const rows = disabled ? SKELETON_ROWS : apiKeys;

  if (!disabled && rows.length === 0) {
    return (
      <p className="text-sm text-muted-foreground">
        API キーがまだ登録されていません。
      </p>
    );
  }

  return (
    <Table>
      <TableHeader>
        <TableRow>
          <TableHead>キー（末尾）</TableHead>
          <TableHead>作成日</TableHead>
          <TableHead>有効期限</TableHead>
        </TableRow>
      </TableHeader>
      <TableBody>
        {rows.map((apiKey) => (
          <TableRow key={apiKey.apiKeyId}>
            <TableCell className="font-mono">
              {disabled ? (
                <Skeleton className="h-4 w-20" />
              ) : (
                <>…{apiKey.suffix}</>
              )}
            </TableCell>
            <TableCell>
              {disabled ? (
                <Skeleton className="h-4 w-24" />
              ) : (
                formatDate(apiKey.createdAt)
              )}
            </TableCell>
            <TableCell>
              {disabled ? (
                <Skeleton className="h-4 w-24" />
              ) : (
                formatDate(apiKey.expiredAt)
              )}
            </TableCell>
          </TableRow>
        ))}
      </TableBody>
    </Table>
  );
}

